"""sklearn.neural_network — Multi-layer Perceptron (numpy only)."""
import numpy as np
from sklearn.base import BaseEstimator, ClassifierMixin, RegressorMixin


def _relu(Z):
    return np.maximum(0, Z)

def _relu_deriv(Z):
    return (Z > 0).astype(float)

def _sigmoid(Z):
    Z = np.clip(Z, -500, 500)
    return 1.0 / (1.0 + np.exp(-Z))

def _softmax(Z):
    e = np.exp(Z - Z.max(axis=1, keepdims=True))
    return e / e.sum(axis=1, keepdims=True)


class MLPClassifier(BaseEstimator, ClassifierMixin):
    """Multi-layer Perceptron classifier.

    Parameters
    ----------
    hidden_layer_sizes : tuple, default=(100,)
    activation : str, default='relu'
    learning_rate_init : float, default=0.001
    max_iter : int, default=200
    random_state : int or None, default=None
    alpha : float, default=0.0001
    batch_size : int, default=200
    tol : float, default=1e-4
    """

    def __init__(self, hidden_layer_sizes=(100,), activation='relu', *,
                 solver='adam', alpha=0.0001, batch_size='auto',
                 learning_rate='constant', learning_rate_init=0.001,
                 power_t=0.5, max_iter=200, shuffle=True, random_state=None,
                 tol=1e-4, verbose=False, warm_start=False, momentum=0.9,
                 nesterovs_momentum=True, early_stopping=False,
                 validation_fraction=0.1, beta_1=0.9, beta_2=0.999,
                 epsilon=1e-8, n_iter_no_change=10, max_fun=15000):
        self.hidden_layer_sizes = hidden_layer_sizes
        self.activation = activation
        self.solver = solver
        self.alpha = alpha
        self.batch_size = 200 if batch_size == 'auto' else batch_size
        self.learning_rate = learning_rate
        self.learning_rate_init = learning_rate_init
        self.power_t = power_t
        self.max_iter = max_iter
        self.shuffle = shuffle
        self.random_state = random_state
        self.tol = tol
        self.verbose = verbose
        self.warm_start = warm_start
        self.momentum = momentum
        self.nesterovs_momentum = nesterovs_momentum
        self.early_stopping = early_stopping
        self.validation_fraction = validation_fraction
        self.beta_1 = beta_1
        self.beta_2 = beta_2
        self.epsilon = epsilon
        self.n_iter_no_change = n_iter_no_change
        self.max_fun = max_fun

    def _init_weights(self, layer_sizes, rng):
        self.coefs_ = []
        self.intercepts_ = []
        for i in range(len(layer_sizes) - 1):
            limit = np.sqrt(6.0 / (layer_sizes[i] + layer_sizes[i + 1]))
            W = rng.uniform(-limit, limit, (layer_sizes[i], layer_sizes[i + 1]))
            b = np.zeros(layer_sizes[i + 1])
            self.coefs_.append(W)
            self.intercepts_.append(b)

    def _forward(self, X):
        activations = [X]
        for i in range(len(self.coefs_) - 1):
            Z = activations[-1] @ self.coefs_[i] + self.intercepts_[i]
            if self.activation == 'relu':
                A = _relu(Z)
            else:
                A = np.tanh(Z)
            activations.append(A)
        Z_out = activations[-1] @ self.coefs_[-1] + self.intercepts_[-1]
        if len(self.classes_) == 2:
            A_out = _sigmoid(Z_out)
        else:
            A_out = _softmax(Z_out)
        activations.append(A_out)
        return activations

    def fit(self, X, y):
        rng = np.random.RandomState(self.random_state)
        X = np.asarray(X, dtype=float)
        y = np.asarray(y)
        self.classes_ = np.unique(y)
        n_classes = len(self.classes_)

        # One-hot encode
        if n_classes == 2:
            Y = (y == self.classes_[1]).astype(float).reshape(-1, 1)
            out_size = 1
        else:
            Y = np.zeros((len(y), n_classes))
            for i, c in enumerate(self.classes_):
                Y[y == c, i] = 1.0
            out_size = n_classes

        layer_sizes = [X.shape[1]] + list(self.hidden_layer_sizes) + [out_size]
        self._init_weights(layer_sizes, rng)

        n = X.shape[0]
        prev_loss = np.inf
        for epoch in range(self.max_iter):
            perm = rng.permutation(n)
            for start in range(0, n, self.batch_size):
                idx = perm[start:start + self.batch_size]
                Xb, Yb = X[idx], Y[idx]
                activations = self._forward(Xb)
                # Backprop
                delta = activations[-1] - Yb
                m = Xb.shape[0]
                for l in range(len(self.coefs_) - 1, -1, -1):
                    dW = activations[l].T @ delta / m + self.alpha * self.coefs_[l]
                    db = delta.mean(axis=0)
                    if l > 0:
                        delta = delta @ self.coefs_[l].T
                        if self.activation == 'relu':
                            delta *= _relu_deriv(activations[l])
                        else:
                            delta *= (1 - activations[l] ** 2)
                    self.coefs_[l] -= self.learning_rate_init * dW
                    self.intercepts_[l] -= self.learning_rate_init * db

            # Loss check
            act = self._forward(X)
            out = act[-1]
            if n_classes == 2:
                loss = -np.mean(Y * np.log(out + 1e-15) + (1 - Y) * np.log(1 - out + 1e-15))
            else:
                loss = -np.mean(np.sum(Y * np.log(out + 1e-15), axis=1))
            if abs(prev_loss - loss) < self.tol:
                break
            prev_loss = loss

        self.n_iter_ = epoch + 1
        return self

    def predict_proba(self, X):
        X = np.asarray(X, dtype=float)
        act = self._forward(X)
        out = act[-1]
        if len(self.classes_) == 2:
            return np.column_stack([1 - out.ravel(), out.ravel()])
        return out

    def predict(self, X):
        proba = self.predict_proba(X)
        return self.classes_[np.argmax(proba, axis=1)]


class MLPRegressor(BaseEstimator, RegressorMixin):
    """Multi-layer Perceptron regressor.

    Parameters
    ----------
    hidden_layer_sizes : tuple, default=(100,)
    activation : str, default='relu'
    learning_rate_init : float, default=0.001
    max_iter : int, default=200
    random_state : int or None, default=None
    alpha : float, default=0.0001
    batch_size : int, default=200
    tol : float, default=1e-4
    """

    def __init__(self, hidden_layer_sizes=(100,), activation='relu', *,
                 solver='adam', alpha=0.0001, batch_size='auto',
                 learning_rate='constant', learning_rate_init=0.001,
                 power_t=0.5, max_iter=200, shuffle=True, random_state=None,
                 tol=1e-4, verbose=False, warm_start=False, momentum=0.9,
                 nesterovs_momentum=True, early_stopping=False,
                 validation_fraction=0.1, beta_1=0.9, beta_2=0.999,
                 epsilon=1e-8, n_iter_no_change=10, max_fun=15000):
        self.hidden_layer_sizes = hidden_layer_sizes
        self.activation = activation
        self.solver = solver
        self.alpha = alpha
        self.batch_size = 200 if batch_size == 'auto' else batch_size
        self.learning_rate = learning_rate
        self.learning_rate_init = learning_rate_init
        self.power_t = power_t
        self.max_iter = max_iter
        self.shuffle = shuffle
        self.random_state = random_state
        self.tol = tol
        self.verbose = verbose
        self.warm_start = warm_start
        self.momentum = momentum
        self.nesterovs_momentum = nesterovs_momentum
        self.early_stopping = early_stopping
        self.validation_fraction = validation_fraction
        self.beta_1 = beta_1
        self.beta_2 = beta_2
        self.epsilon = epsilon
        self.n_iter_no_change = n_iter_no_change
        self.max_fun = max_fun

    def fit(self, X, y):
        rng = np.random.RandomState(self.random_state)
        X = np.asarray(X, dtype=float)
        y = np.asarray(y, dtype=float)
        if y.ndim == 1:
            y = y.reshape(-1, 1)
        self.n_outputs_ = y.shape[1]

        layer_sizes = [X.shape[1]] + list(self.hidden_layer_sizes) + [self.n_outputs_]
        self.coefs_ = []
        self.intercepts_ = []
        for i in range(len(layer_sizes) - 1):
            limit = np.sqrt(6.0 / (layer_sizes[i] + layer_sizes[i + 1]))
            self.coefs_.append(rng.uniform(-limit, limit, (layer_sizes[i], layer_sizes[i + 1])))
            self.intercepts_.append(np.zeros(layer_sizes[i + 1]))

        n = X.shape[0]
        prev_loss = np.inf
        for epoch in range(self.max_iter):
            perm = rng.permutation(n)
            for start in range(0, n, self.batch_size):
                idx = perm[start:start + self.batch_size]
                Xb, Yb = X[idx], y[idx]
                # Forward
                activations = [Xb]
                for i in range(len(self.coefs_) - 1):
                    Z = activations[-1] @ self.coefs_[i] + self.intercepts_[i]
                    activations.append(_relu(Z) if self.activation == 'relu' else np.tanh(Z))
                out = activations[-1] @ self.coefs_[-1] + self.intercepts_[-1]
                activations.append(out)

                # Backprop
                delta = (out - Yb) / Xb.shape[0]
                for l in range(len(self.coefs_) - 1, -1, -1):
                    dW = activations[l].T @ delta + self.alpha * self.coefs_[l]
                    db = delta.mean(axis=0)
                    if l > 0:
                        delta = delta @ self.coefs_[l].T
                        if self.activation == 'relu':
                            delta *= _relu_deriv(activations[l])
                        else:
                            delta *= (1 - activations[l] ** 2)
                    self.coefs_[l] -= self.learning_rate_init * dW
                    self.intercepts_[l] -= self.learning_rate_init * db

            # Loss
            act = [X]
            for i in range(len(self.coefs_) - 1):
                Z = act[-1] @ self.coefs_[i] + self.intercepts_[i]
                act.append(_relu(Z) if self.activation == 'relu' else np.tanh(Z))
            pred = act[-1] @ self.coefs_[-1] + self.intercepts_[-1]
            loss = np.mean((pred - y) ** 2)
            if abs(prev_loss - loss) < self.tol:
                break
            prev_loss = loss

        self.n_iter_ = epoch + 1
        return self

    def predict(self, X):
        X = np.asarray(X, dtype=float)
        a = X
        for i in range(len(self.coefs_) - 1):
            a = a @ self.coefs_[i] + self.intercepts_[i]
            a = _relu(a) if self.activation == 'relu' else np.tanh(a)
        out = a @ self.coefs_[-1] + self.intercepts_[-1]
        return out.ravel() if self.n_outputs_ == 1 else out
